*/

module.exports = pool;

const express = require('express');
const router = express.Router();
const multer = require('multer');
const path = require('path');
const pool = require('../db');

const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, path.join(__dirname, '../uploads')),
    filename: (req, file, cb) => {
        const ext = path.extname(file.originalname);
        cb(null, `site_${Date.now()}${ext}`);
    },
});
const upload = multer({ storage, limits: { fileSize: 10 * 1024 * 1024 } });

// POST /site-progress  ΓÇö upload photo + form data
router.post('/', upload.single('photo'), async (req, res) => {
    // photoUrl can come from body (Supabase) or req.file (local)
    const { projectName, partner, milestone, location, notes, userId, glassCount } = req.body;
    let photoUrl = req.body.photoUrl; // Direct URL from Supabase
    
    if (!photoUrl && req.file) {
        photoUrl = `/uploads/${req.file.filename}`;
    }

    try {
        const result = await pool.query(
            `INSERT INTO site_progress (project_name, partner, milestone, location, notes, photo_url, user_id, glass_count)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8) RETURNING *`,
            [projectName, partner, milestone, location, notes, photoUrl, userId, parseInt(glassCount) || 0]
        );
        const progress = result.rows[0];

        // Create notification
        await pool.query(
            'INSERT INTO notifications (type, title, message, time, user_id) VALUES ($1, $2, $3, $4, $5)',
            ['success', 'Milestone Update', `${projectName} progress updated: ${milestone}.`, 'Just now', userId]
        );

        res.json(progress);
    } catch (err) {
        console.error(err);
        res.status(500).json({ error: 'Failed to save site progress.' });
    }
});

// GET /site-progress
router.get('/', async (req, res) => {
    try {
        const result = await pool.query('SELECT * FROM site_progress ORDER BY created_at DESC');
        res.json(result.rows);
    } catch (err) {
        res.status(500).json({ error: 'Failed to fetch site progress.' });
    }
});

// GET /site-progress/project/:name
router.get('/project/:name', async (req, res) => {
    try {
        const result = await pool.query(
            'SELECT * FROM site_progress WHERE project_name = $1 ORDER BY created_at DESC',
            [req.params.name]
        );
        res.json(result.rows);
    } catch (err) {
        console.error(err);
        res.status(500).json({ error: 'Failed to fetch project progress.' });
    }
});

module.exports = router;

const express = require('express');
const router = express.Router();
const multer = require('multer');
const path = require('path');
const pool = require('../db');

const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, path.join(__dirname, '../uploads')),
    filename: (req, file, cb) => {
        const ext = path.extname(file.originalname);
        cb(null, `user_${req.params.id}_${Date.now()}${ext}`);
    },
});
const upload = multer({ storage, limits: { fileSize: 5 * 1024 * 1024 } }); // 5MB max

// POST /upload/:id/photo
router.post('/:id/photo', upload.single('photo'), async (req, res) => {
    if (!req.file) return res.status(400).json({ error: 'No file uploaded.' });
    try {
        const imageUrl = `/uploads/${req.file.filename}`;
        await pool.query(
            'UPDATE users SET profile_picture_url = $1 WHERE id = $2',
            [imageUrl, req.params.id]
        );
        res.json({ imageUrl });
    } catch (err) {
        console.error(err);
        res.status(500).json({ error: 'Failed to save photo.' });
    }
});

module.exports = router;

const express = require('express');
const cors = require('cors');

const authRoutes = require('./routes/auth');
const projectsRoutes = require('./routes/projects');
const tasksRoutes = require('./routes/tasks');
const notificationsRoutes = require('./routes/notifications');
const usersRoutes = require('./routes/users');
const uploadRoutes = require('./routes/upload');
const siteProgressRoutes = require('./routes/siteProgress');
const inventoryRoutes = require('./routes/inventory');
const path = require('path');

const app = express();
app.use(cors());
app.use(express.json());
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

app.use('/auth', authRoutes);
app.use('/projects', projectsRoutes);
app.use('/tasks', tasksRoutes);
app.use('/notifications', notificationsRoutes);
app.use('/users', usersRoutes);
app.use('/upload', uploadRoutes);
app.use('/site-progress', siteProgressRoutes);
app.use('/inventory', inventoryRoutes);

app.get('/', (req, res) => res.send('BuildSphere API is running Γ£à'));

const PORT = 3001;
app.listen(PORT, () => {
    console.log(`Γ£à BuildSphere API running at http://localhost:${PORT}`);
});

import React, { useState } from "react";
import {
  View, Text, TextInput, TouchableOpacity, Image,
  Keyboard, TouchableWithoutFeedback, Alert, ActivityIndicator
} from "react-native";
import { LinearGradient } from "expo-linear-gradient";
import { KeyboardAwareScrollView } from "react-native-keyboard-aware-scroll-view";
import { API_URL } from "../../lib/api";
import { UserInfo } from "../../App";

interface LoginScreenProps {
  onLogin: (user: UserInfo, token: string) => void;
  onSwitchToSignup: () => void;
  onForgotPassword?: () => void;
}

const PRIMARY = "#7370FF";

export default function LoginScreen({ onLogin, onSwitchToSignup, onForgotPassword }: LoginScreenProps) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    if (!email.trim() || !password.trim()) {
      Alert.alert("Missing info", "Please enter your email and password.");
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`${API_URL}/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      if (!res.ok) {
        Alert.alert("Login Failed", data.error || "Something went wrong.");
        return;
      }
      onLogin(data.user, data.token);
    } catch (err) {
      Alert.alert("Connection Error", "Could not reach the server. Make sure the backend is running.");
    } finally {
      setLoading(false);
    }
  };

  const inputBoxStyle = {
    shadowColor: PRIMARY, shadowOpacity: 0.18, shadowRadius: 10,
    shadowOffset: { width: 0, height: 6 }, elevation: 3,
    borderWidth: 1, borderColor: "#E7E7EE",
  } as const;

  return (
    <TouchableWithoutFeedback onPress={Keyboard.dismiss} accessible={false}>
      <View className="flex-1 bg-white">
        <KeyboardAwareScrollView
          contentContainerStyle={{ flexGrow: 1, justifyContent: "center", alignItems: "center", paddingHorizontal: 24, paddingVertical: 40 }}
          enableOnAndroid extraScrollHeight={18} keyboardOpeningTime={220}
          keyboardShouldPersistTaps="handled" showsVerticalScrollIndicator={false}
        >
          <View className="w-full max-w-[360px] items-center">
            <Image source={require("../../assets/Buildspherelogo4x.png")} style={{ width: 56, height: 56 }} resizeMode="contain" />
            <Text className="mt-5 text-[22px] font-bold text-[#1E1E1E]">Log In to BuildSphere</Text>
            <View className="flex-row items-center mt-2">
              <Text className="text-[12.5px] text-[#A3A3A3]">Don't have an account?{" "}</Text>
              <TouchableOpacity onPress={onSwitchToSignup}>
                <Text className="text-[12.5px] font-semibold text-[#7370FF]">Sign Up</Text>
              </TouchableOpacity>
            </View>

            <View className="w-full mt-10">
              <Text className="text-[12px] font-semibold text-[#2D2D2D] mb-2">Email</Text>
              <View className="bg-white rounded-xl" style={inputBoxStyle}>
                <TextInput value={email} onChangeText={setEmail} placeholder="Enter your email"
                  placeholderTextColor="#B9B9B9" autoCapitalize="none" keyboardType="email-address"
                  className="px-4 h-[52px]" />
              </View>

              <Text className="text-[12px] font-semibold text-[#2D2D2D] mb-2 mt-6">Password</Text>
              <View className="bg-white rounded-xl" style={inputBoxStyle}>
                <TextInput value={password} onChangeText={setPassword} placeholder="Enter your password"
                  placeholderTextColor="#B9B9B9" secureTextEntry className="px-4 h-[52px]" />
              </View>

              <TouchableOpacity onPress={handleLogin} disabled={loading}
                className="mt-10 rounded-xl h-[52px] justify-center items-center bg-[#7370FF] shadow-lg">
                {loading ? <ActivityIndicator color="white" /> : <Text className="text-white font-semibold text-[15px]">Log In</Text>}
              </TouchableOpacity>


              <TouchableOpacity onPress={onForgotPassword} className="self-center mt-6">
                <Text className="text-[12px] text-[#B8B8B8]">Forgot Password?</Text>
              </TouchableOpacity>
            </View>
          </View>
        </KeyboardAwareScrollView>

        {/* TOP LAYER GRADIENT */}
        <LinearGradient
          colors={["rgba(115,112,255,0.6)", "transparent"]}
          start={{ x: 0.5, y: 0 }} end={{ x: 0.5, y: 1 }}
          className="absolute top-0 left-0 right-0 h-[450px]"
          pointerEvents="none"
        />
      </View>
    </TouchableWithoutFeedback>
  );
}

import React, { useState } from "react";
import { View, Text, TouchableOpacity, ScrollView, Modal, Platform, Image, Dimensions } from "react-native";
import { Ionicons } from "@expo/vector-icons";
import { LinearGradient } from "expo-linear-gradient";

const { width } = Dimensions.get('window');

interface TaskDetailScreenProps {
    visible: boolean;
    task: any;
    onClose: () => void;
}

interface Comment {
    id: number;
    user: string;
    initials: string;
    text: string;
    avatarBg: string;
    avatarText: string;
}

const PRIMARY = "#7370FF";

export default function TaskDetailScreen({ visible, task, onClose }: TaskDetailScreenProps) {
    if (!task) return null;

    const [activeSection, setActiveSection] = useState<"detail" | "comments">("detail");

    const getStatusStyle = (status: string) => {
        switch (status?.toLowerCase()) {
            case "in-progress": return { bg: "#EAE8FF", text: "#7370FF", label: "In Progress" };
            case "completed": return { bg: "#E8F5E9", text: "#4CAF50", label: "Completed" };
            case "to-review": return { bg: "#FFF4E5", text: "#FF9800", label: "To Review" };
            default: return { bg: "#EAE8FF", text: "#7370FF", label: "In Progress" };
        }
    };

    const statusStyle = getStatusStyle(task.status);
    const comments: Comment[] = [];
    const priorityColor = task.priority?.toLowerCase() === 'high' ? '#FF6B6B' : '#FFA500';

    return (
        <Modal visible={visible} animationType="slide" transparent={false}>
            <View className="flex-1 bg-white">
                {/* Header */}
                <View className="flex-row items-center px-5 pt-12 pb-4">
                    <TouchableOpacity onPress={onClose} className="mr-3">
                        <Ionicons name="chevron-back" size={32} color="#1E1E1E" />
                    </TouchableOpacity>
                    <Text className="text-[32px] font-bold text-[#7370FF]">Task Details</Text>
                </View>

                <ScrollView className="flex-1 px-5" showsVerticalScrollIndicator={false} contentContainerStyle={{ paddingBottom: 120 }}>
                    {/* Status & Title Card */}
                    <View className="bg-white rounded-[24px] p-6 mb-8 border border-[#F0F0F0]"
                        style={{ shadowColor: "#000", shadowOpacity: 0.04, shadowRadius: 10, elevation: 2 }}>
                        <View className="flex-row items-center justify-between mb-4">
                            <Text className="text-[20px] font-bold text-[#1E1E1E] flex-1 mr-4">{task.title}</Text>
                            <View className="px-5 py-2 rounded-full" style={{ backgroundColor: statusStyle.bg }}>
                                <Text className="text-[11px] font-bold uppercase tracking-wider" style={{ color: statusStyle.text }}>
                                    {statusStyle.label}
                                </Text>
                            </View>
                        </View>
                        <Text className="text-[14px] text-[#A3A3A3] leading-6">
                            {task.description || "The task involves technical drawings and layouts required for the initial construction phase. Please ensure all details are accurate and adhere to project standards."}
                        </Text>
                    </View>

                    {/* Metadata Grid */}
                    <View className="mb-8">
                        {/* Row 1: Phase, Milestone, Priority */}
                        <View className="flex-row mb-6">
                            <View className="flex-1">
                                <Text className="text-[12px] text-[#A3A3A3] mb-1 font-medium">Phase</Text>
                                <Text className="text-[15px] font-bold text-[#1E1E1E]">{task.phase || "Phase 1"}</Text>
                            </View>
                            <View className="flex-1 items-center">
                                <Text className="text-[12px] text-[#A3A3A3] mb-1 font-medium">Milestone</Text>
                                <Text className="text-[15px] font-bold text-[#1E1E1E]">{task.milestone || "Milestone 1"}</Text>
                            </View>
                            <View className="flex-1 items-end">
                                <Text className="text-[12px] text-[#A3A3A3] mb-1 font-medium">Priority</Text>
                                <Text className="text-[15px] font-bold" style={{ color: priorityColor }}>
                                    {task.priority || "High"}
                                </Text>
                            </View>
                        </View>

                        {/* Row 2: Dates */}
                        <View className="flex-row">
                            <View className="flex-1">
                                <Text className="text-[12px] text-[#A3A3A3] mb-1 font-medium">Start Date</Text>
                                <Text className="text-[15px] font-bold text-[#1E1E1E]">{task.start_date || "01/31/2026"}</Text>
                            </View>
                            <View className="flex-1 items-end">
                                <Text className="text-[12px] text-[#A3A3A3] mb-1 font-medium">End Date</Text>
                                <Text className="text-[15px] font-bold text-[#1E1E1E]">{task.due_date || "02/28/2026"}</Text>
                            </View>
                        </View>
                    </View>

                    {/* Task Photos Section */}
                    <View className="mb-8">
                        <Text className="text-[18px] font-bold text-[#1E1E1E] mb-4">Task Photos</Text>
                        <TouchableOpacity 
                            className="w-full h-[60px] bg-[#EAE8FF] rounded-[16px] border border-dashed border-[#7370FF] items-center justify-center flex-row mb-4"
                        >
                            <Ionicons name="camera-outline" size={24} color="#7370FF" />
                            <Text className="text-[#7370FF] font-bold ml-3">Add a Task Photo</Text>
                        </TouchableOpacity>

                        {/* Dummy Photo Gird */}
                        <View className="flex-row gap-3">
                            <View className="w-[80px] h-[80px] bg-[#F5F5F7] rounded-[12px] overflow-hidden">
                                <Image source={{ uri: 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?auto=format&fit=crop&q=80&w=300' }} className="w-full h-full" />
                            </View>
                            <View className="w-[80px] h-[80px] bg-[#F5F5F7] rounded-[12px] overflow-hidden">
                                <Image source={{ uri: 'https://images.unsplash.com/photo-1503387762-592dee58c460?auto=format&fit=crop&q=80&w=300' }} className="w-full h-full" />
                            </View>
                        </View>
                    </View>

                    {/* Comments Section */}
                    <View className="bg-[#F6F6FF] rounded-[24px] p-6 mb-10 border border-[#EDECFF]">
                        <Text className="text-[18px] font-bold text-[#1E1E1E] mb-6">Comments</Text>

                        {comments.map((comment, index) => (
                            <View key={comment.id} className={`flex-row items-center ${index !== comments.length - 1 ? 'mb-6' : ''}`}>
                                <View 
                                    className="w-10 h-10 rounded-full items-center justify-center mr-4"
                                    style={{ backgroundColor: comment.avatarBg }}
                                >
                                    <Text className="text-[12px] font-bold" style={{ color: comment.avatarText }}>
                                        {comment.initials}
                                    </Text>
                                </View>
                                <Text className="text-[15px] font-medium text-[#1E1E1E] flex-1">
                                    {comment.text}
                                </Text>
                            </View>
                        ))}
                    </View>
                </ScrollView>

                {/* Bottom Navigation Mimic */}
                <View className="h-[90px] border-t border-[#F5F5F7] flex-row items-center justify-between px-10 pb-4">
                    <TouchableOpacity className="items-center">
                        <Ionicons name="home-outline" size={24} color="#9A9A9A" />
                        <Text className="text-[10px] text-[#9A9A9A] mt-1">Home</Text>
                    </TouchableOpacity>
                    <TouchableOpacity className="items-center">
                        <View className="w-12 h-12 bg-[#F0F0F0] rounded-2xl items-center justify-center mb-1">
                            <Ionicons name="briefcase" size={24} color="#7370FF" />
                        </View>
                        <Text className="text-[10px] text-[#7370FF] font-bold">My work</Text>
                    </TouchableOpacity>
                    <TouchableOpacity className="items-center">
                        <Ionicons name="notifications-outline" size={24} color="#9A9A9A" />
                        <Text className="text-[10px] text-[#9A9A9A] mt-1">Notifications</Text>
                    </TouchableOpacity>
                    <TouchableOpacity className="items-center">
                        <Ionicons name="ellipsis-horizontal-outline" size={24} color="#9A9A9A" />
                        <Text className="text-[10px] text-[#9A9A9A] mt-1">More</Text>
                    </TouchableOpacity>
                </View>
            </View>
        </Modal>
    );
}
